  @Field var value: Double = 0
  var onValueChange = EventDispatcher()
}

struct SliderView: ExpoSwiftUI.View {
  @ObservedObject var props: SliderProps

  var body: some View {
    Slider(value: Binding(
      get: { props.value },
      set: { props.onValueChange(["value": $0]) }
    ))
  }
}

